import * as React from "react";
import {
  Box,
  NavLink,
  Button,
  Heading,
  Flex,
  Link,
  BaseStyles,
  Text,
} from "theme-ui";
import { useOverlayTriggerState } from "@react-stately/overlays";
import { Link as GatsbyLink } from "gatsby";
import Subscribe from "./Subscribe";
import Modal from "./Modal";
import { SUBSCRIBE_TITLE } from "../config";
import { External, RSS, Twitter, Telegram, Email } from "./Icons";
import { getPageType } from "../utils";
export default function ({ meta, location }) {
  const pageType = getPageType(location.pathname);
  const rssHref =
    pageType === "week"
      ? `/${meta.repo}/week/rss.xml`
      : `/${meta.repo}/rss.xml`;
  let state = useOverlayTriggerState({});
  return (
    <Box sx={{ maxWidth: "5xl" }}>
      {state.isOpen && (
        <Modal title={SUBSCRIBE_TITLE} onClose={state.close}>
          <Subscribe onClose={state.close}></Subscribe>
        </Modal>
      )}
      <Flex
        sx={{
          fontSize: 2,
          justifyContent: "space-between",
          flexWrap: "wrap",
        }}
      >
        <Box pb="1">
          <Text>View by</Text>
          <NavLink
            as={GatsbyLink}
            disabled={pageType === "day" ? true : false}
            variant={pageType === "day" ? "navActive" : "nav"}
            to={pageType === "day" ? `` : `/${meta.repo}`}
          >
            DAY
          </NavLink>
          /
          <NavLink
            as={GatsbyLink}
            disabled={pageType === "week" ? true : false}
            variant={pageType === "week" ? "navActive" : "nav"}
            to={pageType === "week" ? `` : `/${meta.repo}/week/`}
          >
            WEEK
          </NavLink>
          /
          <NavLink
            as={GatsbyLink}
            disabled={pageType === "readme" ? true : false}
            variant={pageType === "readme" ? "navActive" : "nav"}
            to={pageType === "readme" ? `` : `/${meta.repo}/readme/`}
          >
            README
          </NavLink>
        </Box>

        <Box pb="1">
          <Link
            title="Twitter"
            target="_blank"
            rel="noopener noreferrer"
            href="https://twitter.com/trackawesome"
            mr="sm"
            variant="external"
          >
            <Twitter></Twitter>
          </Link>
          <Link
            title="Telegram"
            target="_blank"
            rel="noopener noreferrer"
            href="https://t.me/trackawesomelist"
            mr="sm"
            variant="external"
          >
            <Telegram></Telegram>
          </Link>
          <Link
            title="RSS"
            target="_blank"
            rel="noopener noreferrer"
            href={rssHref}
            mr="sm"
            variant="external"
          >
            <RSS></RSS>
          </Link>
          <Button title="Email" onClick={state.open} mr="sm" variant="textLink">
            <Email></Email>
          </Button>
          <Link
            target="_blank"
            rel="noopener noreferrer"
            href={`https://github.com/${meta.repo}`}
            variant="external"
          >
            View on Github
            <External></External>
          </Link>
        </Box>
      </Flex>
    </Box>
  );
}
